def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 1.0
        factor = 0.9
        penalty = 0.0
        adjustment = 1.0
        influence = 0.0
        threshold_passed = False
        for j in range(1, 15):
            mod_val = (cap + j*j + i) % 11
            if mod_val < 3:
                score += np.tanh(ratio * j) * (j ** 1.5) / (mod_val + 1)
            elif mod_val < 7:
                score += np.exp(-ratio * j / (mod_val + 2)) * j
            else:
                score -= np.log1p(ratio + j / (mod_val + 3)) * j * 0.5
            if j % 4 == 0:
                factor *= 1 + 0.02 * (j % 5) - 0.01 * (j % 3)
            else:
                factor *= 0.95 + 0.005 * (j % 7)
            if cap % (j+2) == 0:
                penalty += np.cos(ratio * j) * (j / (j + 1))
            else:
                penalty -= np.sin(ratio * j * 0.5) * 0.3
            if j == 7:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            influence += np.log1p(diff) / (k + 2)
                        else:
                            influence -= np.sqrt(abs(diff)) / (k + 4)
                    else:
                        influence -= abs(diff)**1.1 / (k + 5)
            if ratio < 0.3 and j % 2 == 1:
                adjustment *= 0.85 + 0.01 * j
            elif ratio > 0.7 and j % 3 == 2:
                adjustment *= 1.1 - 0.015 * j
            if (i + j + cap) % 13 == 0:
                threshold_passed = True
        score = (score * factor + penalty * 0.9 - influence * 0.7) * adjustment
        if score < 0:
            priorities[i] = -score * (np.log1p(cap + item) + np.sqrt(cap + i))
            if threshold_passed:
                priorities[i] *= 1.1 + 0.01 * (i % 5)
            else:
                priorities[i] *= 0.95 - 0.005 * (i % 3)
        else:
            exp_factor = np.exp(-ratio**1.5)
            if cap > item * 3:
                priorities[i] = -score / (np.cbrt(cap) + 1) * (1.2 + ratio) * exp_factor
            else:
                priorities[i] = -score / (cap + 5) * exp_factor * (0.8 + 0.02 * i)
            if threshold_passed:
                priorities[i] *= 1.05
            else:
                priorities[i] *= 0.97
        if cap % 3 == 0:
            priorities[i] *= 0.99
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.1:
            priorities[i] *= 0.7
    return priorities
